export const ORDER_TIMELINE_BODY_JS = "\nfunction renderBody(oai, out){\n  oai = oai || {}\n  var root = document.getElementById('root')\n  function el(t,c,x){ var n=document.createElement(t); if(c)n.className=c; if(x!=null)n.textContent=String(x); return n }\n  function row(box,k,v){ var r=el('div','row'); r.appendChild(el('span',null,k)); r.appendChild(el('span',null,v)); box.appendChild(r) }\n  function localTime(iso){ try { return new Date(String(iso).replace(' ','T')+(String(iso).includes('Z')||String(iso).includes('+')?'':'Z')).toLocaleString() } catch(e){ return String(iso) } }\n  root.textContent=''\n  if(!out||!out.schema_version){ root.textContent='WebAZ: no structured payload visible to this widget.'; return }\n  var box=el('div','box'); root.appendChild(box)\n  var sv=String(out.schema_version)\n\n  if(sv==='webaz.order_status.model.v1'){\n    if(out.up_to_date){ box.appendChild(el('div','h','и®ўеҚ• '+out.order_id+' ж— ж–°еҸҳеҢ–')); box.appendChild(el('div','meta','зҠ¶жҖҒ:'+(out.status||'')+' В· еўһйҮҸеҲ·ж–°:иҮӘ updated_since иө·ж— еӯҳеӮЁжҖҒеҸҳеҢ–')); return }\n    if(out.order){\n      var mo=out.order\n      box.appendChild(el('div','h','и®ўеҚ• '+String(mo.order_id||'')))\n      row(box,'зҠ¶жҖҒ',String(mo.status||''))\n      if(mo.next_actor) row(box,'дёӢдёҖиҙЈд»»ж–№',String(mo.next_actor))\n      if(mo.deadline) row(box,'жҲӘжӯўж—¶й—ҙ',localTime(mo.deadline))\n      if(typeof oai.callTool==='function'){\n        var mb=el('div','rowbtn'); var mf=el('button',null,'жҹҘзңӢе®Ңж•ҙж—¶й—ҙзәҝ')\n        mf.addEventListener('click',onceGuard(function(){ oai.callTool('webaz_buyer_orders',{order_id:mo.order_id,full:true}) }))\n        mb.appendChild(mf); box.appendChild(mb)\n      }\n      return\n    }\n    box.appendChild(el('div','h','д№°е®¶и®ўеҚ•'))\n    var s=out.summary||{}\n    box.appendChild(el('div','meta','е…ұ '+(s.total||0)+' еҚ• В· жҙ»и·ғ '+(s.active||0)+' В· дәүи®® '+(s.disputed||0)))\n    ;(out.orders||[]).forEach(function(o){\n      var r=el('div','row'); r.appendChild(el('span',null,String(o.order_id).slice(0,12)+'вҖҰ')); r.appendChild(el('span',null,String(o.status)))\n      if(typeof oai.callTool==='function'){ r.style.cursor='pointer'; r.addEventListener('click',onceGuard(function(){ oai.callTool('webaz_buyer_orders',{order_id:o.order_id,full:true}) })) }\n      box.appendChild(r)\n    })\n    return\n  }\n\n  if(sv!=='webaz.order_timeline.model.v1'&&sv!=='webaz.order_timeline.model.v2'){ box.textContent='дёҚж”ҜжҢҒжӯӨж—§еҚЎзүҮзүҲжң¬(schema_version='+sv+')гҖӮиҜ·еңЁ WebAZ PWA жҹҘзңӢжңҖж–°зҠ¶жҖҒгҖӮ'; return }\n  box.appendChild(el('div','h',(out.product&&out.product.title)||String(out.order_id||'')))\n  box.appendChild(el('div','price',(out.price&&out.price.display)||''))\n  if(out.fiat_estimate) box.appendChild(el('div','fiat',out.fiat_estimate.display+(out.fiat_estimate.stale?'(иҝ‘дјјжұҮзҺҮ)':'')))\n  box.appendChild(el('div','badge',String(out.rail_badge||'')))\n  box.appendChild(el('div','st',(out.status&&out.status.label)||''))\n  if(out.next_actor) row(box,'дёӢдёҖиҙЈд»»ж–№',String(out.next_actor))\n  if(out.deadline&&out.deadline.iso) row(box,'жҲӘжӯўж—¶й—ҙ',localTime(out.deadline.iso))\n  var lg=out.logistics||{}\n  // BUG-02:дёүз§Қй…ҚйҖҒж—¶й—ҙеҲҶеҲ— вҖ”вҖ” в‘ дёӢеҚ•ж—¶йў„и®Ўй…ҚйҖҒ(promised_eta,еҶ»з»“жүҝиҜә)в‘ЎеҪ“еүҚзү©жөҒйў„и®Ў(shipping_est_days,иҝҗиҙ№жЁЎжқҝ;йқһжүҝиҜә)в‘ўзү©жөҒиҝҪиёӘгҖӮ\n  //   дёӨз§Қ ETA з»қдёҚеҗҲжҲҗдёҖдёӘж Үзӯҫ;ж—§еҚ•ж— жүҝиҜәеҝ«з…§ вҶ’ \"дёӢеҚ•ж—¶жңӘи®°еҪ•йў„и®Ўй…ҚйҖҒж—¶й—ҙ\";еҸӘжҳҫзӨә\"зәҰNеӨ©/иҢғеӣҙ\",дёҚдјӘйҖ зЎ®е®ҡж—ҘжңҹгҖӮ\n  var pe=lg.promised_eta\n  function etaText(e){ if(!e) return null; if(e.legacy_missing) return 'дёӢеҚ•ж—¶жңӘи®°еҪ•йў„и®Ўй…ҚйҖҒж—¶й—ҙ'; if(e.estimated_days_text==null) return 'ж— й…ҚйҖҒдј°и®Ў'; var lo=e.estimated_min_days, hi=e.estimated_max_days; if(lo!=null&&hi!=null) return (lo===hi?('зәҰ'+lo+'еӨ©'):(lo+'вҖ“'+hi+'еӨ©')); return String(e.estimated_days_text)+'еӨ©' }\n  var petxt=etaText(pe); if(petxt) row(box,'дёӢеҚ•ж—¶йў„и®Ўй…ҚйҖҒ',petxt)\n  if(lg.shipping_est_days!=null) row(box,'еҪ“еүҚзү©жөҒйў„и®Ў',String(lg.shipping_est_days)+'еӨ©')\n  if(lg.tracking) row(box,'зү©жөҒеҚ•еҸ·',String(lg.tracking))\n  var tl=el('div','tl')\n  ;(out.timeline||[]).forEach(function(t){ tl.appendChild(el('div',null,localTime(t.at)+' В· '+((t.to_status&&t.to_status.label)||'')+(t.actor?'('+t.actor+')':''))) })\n  box.appendChild(tl)\n  if(out.refund){\n    var w=el('div','warn')\n    w.appendChild(el('b',null,'йҖҖж¬ҫ/йҖҖиҙ§'))\n    ;(out.refund.requests||[]).forEach(function(x){ w.appendChild(el('div',null,String(x.status)+' В· '+((x.amount&&x.amount.display)||'')+' В· '+String(x.created_at||''))) })\n    w.appendChild(el('div','meta',String(out.refund.note||'')))\n    box.appendChild(w)\n  }\n  var btns=el('div','rowbtn')\n  if(typeof oai.callTool==='function'){\n    var rf=el('button',null,'еҲ·ж–°')\n    rf.addEventListener('click',onceGuard(function(){ oai.callTool('webaz_buyer_orders',{order_id:out.order_id,full:true}) }))   // еўһйҮҸиҜӯд№үеңЁжңҚеҠЎз«Ҝ updated_since;жӯӨеӨ„е…ЁиҜ»дҝқиҜҒеҠЁдҪңйқўж–°йІң\n    btns.appendChild(rf)\n  }\n  if(out.order_id){\n    // В§V DIRECT_TOOL:гҖҢиҒ”зі»е•Ҷе®¶гҖҚ= иҜ»дјҡиҜқ(order_chat list)+ еҸ‘ж¶ҲжҒҜ(order_chat send)з»“жһ„еҢ–зӣҙи°ғ,йӣ¶иҮӘз„¶иҜӯиЁҖгҖҒйӣ¶жЁЎеһӢйҖүе·Ҙе…·гҖӮ\n    //   дјҡиҜқе°ұең°жёІжҹ“;еҸ‘йҖҒжӯЈж–Үз”ұз”ЁжҲ·еңЁиҫ“е…ҘжЎҶжҳҺзЎ®иҫ“е…Ҙ,жҳҺзЎ®ж ҮжіЁгҖҢеҸ‘з»ҷи®ўеҚ•еҜ№ж–№гҖҚ;single-flight + зЁіе®ҡе№Ӯзӯүй”®;ж—  alert/confirmгҖӮ\n    //   е®ҝдё»дёҚж”ҜжҢҒз»„д»¶зӣҙи°ғ вҶ’ fail-visible + fallback_reason,дёҚжҠҠжӯЈж–ҮиҮӘеҠЁеҸ‘з»ҷжЁЎеһӢгҖӮеҸӮдёҺиҖ…/еҸҚиҜҲ/block/йҷҗйў‘/е№Ӯзӯүж ЎйӘҢе…ЁеңЁжңҚеҠЎз«ҜдёҚеҸҳгҖӮ\n    function shash(s){ var h=5381; for(var i=0;i<s.length;i++){ h=((h<<5)+h+s.charCodeAt(i))>>>0 } return h.toString(36) }\n    var chatBtn=el('button',null,'иҒ”зі»е•Ҷе®¶')\n    var chatPanel=el('div','chatpanel'); chatPanel.style.display='none'\n    var chatMsgs=el('div','chatmsgs'); chatPanel.appendChild(chatMsgs)\n    function renderChat(r){\n      var d=(r&&r.structuredContent)?r.structuredContent:r; chatMsgs.textContent=''\n      var msgs=(d&&(d.messages||d.conversation||d.items))||[]\n      if(!msgs.length){ chatMsgs.appendChild(el('div','meta','жҡӮж— ж¶ҲжҒҜ')); return }\n      msgs.forEach(function(m){ var who=(m.sender||m.from||''); chatMsgs.appendChild(el('div','meta',(who?who+': ':'')+String(m.body||m.text||''))) })\n    }\n    function loadChat(){\n      if(typeof oai.callTool!=='function') return false\n      chatMsgs.textContent='иҜ»еҸ–дёӯвҖҰ'\n      try{ var p=oai.callTool('webaz_order_chat',{action:'list',order_id:out.order_id}); if(p&&typeof p.then==='function'){ p.then(renderChat,function(){ chatMsgs.textContent='иҜ»еҸ–еӨұиҙҘ,иҜ·йҮҚиҜ•' }) } else { chatMsgs.textContent='е·ІиҜ·жұӮ(зӯүеҫ…е®ҝдё»еӣһдј )' } }catch(e){ chatMsgs.textContent='иҜ»еҸ–еӨұиҙҘ' }\n      return true\n    }\n    var inp=document.createElement('textarea'); inp.className='chatinput'; inp.setAttribute('rows','2'); inp.setAttribute('maxlength','2000'); inp.setAttribute('placeholder','з»ҷи®ўеҚ•еҜ№ж–№зҡ„ж¶ҲжҒҜ(е°ҶеҸ‘йҖҒз»ҷеҜ№ж–№)')\n    var sendBtn=el('button','btn','еҸ‘йҖҒз»ҷи®ўеҚ•еҜ№ж–№'); var sending=false\n    sendBtn.addEventListener('click',function(){\n      if(sending) return\n      var body=String(inp.value||'').trim()\n      if(!body){ chatMsgs.appendChild(el('div','meta','иҜ·иҫ“е…Ҙж¶ҲжҒҜеҶ…е®№')); return }\n      if(body.length>2000){ chatMsgs.appendChild(el('div','meta','ж¶ҲжҒҜиҝҮй•ҝ(вүӨ2000)')); return }\n      if(typeof oai.callTool!=='function'){ try{ console.warn('[webaz-widget] chat_send fallback_reason=HOST_COMPONENT_TOOL_CALL_UNAVAILABLE') }catch(e){} chatMsgs.appendChild(el('div','meta','жӯӨе®ҝдё»дёҚж”ҜжҢҒз»„д»¶еҸ‘йҖҒ;иҜ·еңЁ webaz.xyz и®ўеҚ•йЎөиҒ”зі»е•Ҷе®¶')); return }\n      sending=true; sendBtn.disabled=true\n      var idem='wgt_'+shash(String(out.order_id)+'|'+body)   // зЁіе®ҡе№Ӯзӯүй”®:еҗҢеҶ…е®№йҮҚиҜ•еӨҚз”Ё(жңҚеҠЎз«Ҝе№Ӯзӯүе…ңеә•);ж”№еҶ…е®№=ж–°й”®\n      try{ var p=oai.callTool('webaz_order_chat',{action:'send',order_id:out.order_id,body:body,idempotency_key:idem})\n        if(p&&typeof p.then==='function'){ p.then(function(){ inp.value=''; sending=false; sendBtn.disabled=false; loadChat() },function(){ sending=false; sendBtn.disabled=false; chatMsgs.appendChild(el('div','meta','еҸ‘йҖҒеӨұиҙҘ,иҜ·йҮҚиҜ•(еҗҢеҶ…е®№йҮҚиҜ•дёҚдјҡйҮҚеӨҚеҸ‘йҖҒ)')) }) }\n        else { sending=false; sendBtn.disabled=false; chatMsgs.appendChild(el('div','meta','е·ІиҜ·жұӮеҸ‘йҖҒ(зӯүеҫ…е®ҝдё»еӣһдј );еҗҢеҶ…е®№йҮҚиҜ•дёҚдјҡйҮҚеӨҚеҸ‘йҖҒ')) }\n      }catch(e){ sending=false; sendBtn.disabled=false }\n    })\n    chatPanel.appendChild(inp); chatPanel.appendChild(sendBtn)\n    chatPanel.appendChild(el('div','meta','ж¶ҲжҒҜе°ҶеҸ‘йҖҒз»ҷи®ўеҚ•еҜ№ж–№ В· иҜ·еӢҝеңЁж¶ҲжҒҜдёӯеЎ«еҶҷең°еқҖ/ж”Ҝд»ҳеҮӯжҚ®/йӘҢиҜҒз Ғ/еҜҶй’Ҙ'))\n    chatBtn.addEventListener('click',onceGuard(function(){\n      if(chatPanel.style.display==='none'){ chatPanel.style.display='block'; if(!loadChat()){ try{ console.warn('[webaz-widget] chat_list fallback_reason=HOST_COMPONENT_TOOL_CALL_UNAVAILABLE') }catch(e){} chatMsgs.textContent=''; chatMsgs.appendChild(el('div','meta','жӯӨе®ҝдё»дёҚж”ҜжҢҒз»„д»¶иҜ»еҸ–;иҜ·еңЁ webaz.xyz и®ўеҚ•йЎөжҹҘзңӢдјҡиҜқ')) } }\n      else { chatPanel.style.display='none' }\n    },1500))\n    btns.appendChild(chatBtn); box.appendChild(chatPanel)\n  }\n  var open=el('button',null,'и®ўеҚ•йЎө(webaz.xyz)')\n  open.addEventListener('click',onceGuard(function(){ openWebaz(oai,'https://webaz.xyz/#order/'+encodeURIComponent(String(out.order_id||''))) }))\n  btns.appendChild(open)\n  box.appendChild(btns)\n  box.appendChild(el('div','meta',String(out.actions_note||'')))\n}"
